import pytest


def partial(fn, *partial_args, **partial_kwargs):
    def wrapper(*args, **kwargs):
        merged = {**partial_kwargs, **kwargs}
        return fn(*partial_args, *args, **merged)
    return wrapper


def test_partial_applies_positional_args():
    def add(a, b, c):
        return a + b + c

    wrapped = partial(add, 1, 2)

    assert wrapped(3) == 6


def test_partial_applies_keyword_args():
    def make_greeting(greeting, name, punctuation="!"):
        return f"{greeting}, {name}{punctuation}"

    wrapped = partial(make_greeting, greeting="Hello", punctuation=".")

    assert wrapped(name="Alice") == "Hello, Alice."


def test_call_time_kwargs_override_partial_kwargs():
    def describe(name, title=None):
        return f"{title} {name}" if title else name

    wrapped = partial(describe, title="Dr.")

    assert wrapped("Smith", title="Prof.") == "Prof. Smith"


def test_partial_and_call_time_args_are_combined_in_order():
    def collect(*args, **kwargs):
        return args, kwargs

    wrapped = partial(collect, 1, 2, a=10)

    args, kwargs = wrapped(3, 4, b=20)

    assert args == (1, 2, 3, 4)
    assert kwargs == {"a": 10, "b": 20}


def test_no_partial_arguments():
    def identity(*args, **kwargs):
        return args, kwargs

    wrapped = partial(identity)

    args, kwargs = wrapped(1, 2, x=3)

    assert args == (1, 2)
    assert kwargs == {"x": 3}


def test_partial_with_only_keyword_arguments():
    def fn(**kwargs):
        return kwargs

    wrapped = partial(fn, a=1, b=2)

    assert wrapped(c=3) == {"a": 1, "b": 2, "c": 3}


def test_partial_with_only_positional_arguments():
    def fn(*args):
        return args

    wrapped = partial(fn, 1, 2)

    assert wrapped(3, 4) == (1, 2, 3, 4)


def test_partial_can_wrap_callable_object():
    class Multiplier:
        def __call__(self, a, b):
            return a * b

    wrapped = partial(Multiplier(), 6)

    assert wrapped(7) == 42


def test_error_when_required_argument_missing():
    def fn(a, b):
        return a + b

    wrapped = partial(fn, 1)

    with pytest.raises(TypeError):
        wrapped()


def test_error_when_too_many_positional_arguments():
    def fn(a, b):
        return a + b

    wrapped = partial(fn, 1, 2)

    with pytest.raises(TypeError):
        wrapped(3)


def test_error_when_function_is_not_callable():
    wrapped = partial(123)

    with pytest.raises(TypeError):
        wrapped()


def test_error_when_positional_and_keyword_conflict():
    def fn(a, b):
        return a + b

    wrapped = partial(fn, 1, b=2)

    with pytest.raises(TypeError):
        wrapped(3)
